103→// ---------------------------------------------------------------------------
104→// Codex event types
105→// ---------------------------------------------------------------------------
106→
107→interface CodexSessionMeta {
108→  type?: 'session_meta';
109→  id: string;
110→  timestamp: string;
111→  cwd?: string;
112→  originator?: string;
113→  source?: string;
114→  cli_version?: string;
115→  model?: string;
116→}
117→
118→interface CodexRolloutLine {
119→  type: string;
120→  payload?: Record<string, unknown>;
121→  // Legacy format: bare events without payload wrapper
122→  [key: string]: unknown;
123→}
124→
125→interface CodexItem {
126→  id?: string;
127→  type: string;
128→  text?: string;
129→  content?: unknown;
130→  command?: string;
131→  cwd?: string;
132→  status?: string;
133→  exitCode?: number;
134→  durationMs?: number;
135→  aggregatedOutput?: string;
136→  changes?: Array<{ path: string; kind: string; diff?: string }>;
137→  server?: string;
138→  tool?: string;
139→  arguments?: Record<string, unknown>;
140→  result?: string;
141→  error?: string;
142→  summary?: string;
143→  query?: string;
144→  action?: string;
145→  path?: string;
146→}
147→
148→interface CodexUsage {
149→  input_tokens?: number;
150→  cached_input_tokens?: number;
151→  output_tokens?: number;
152→  reasoning?: number;
153→}
154→
155→// ---------------------------------------------------------------------------
156→// Parser
157→// ---------------------------------------------------------------------------
158→
159→function parseCodexSession(filePath: string): ParsedSession | null {
160→  try {
161→    const content = fs.readFileSync(filePath, 'utf-8');
162→    const lines = content.split('\n').filter(line => line.trim());
163→    if (lines.length === 0) return null;
164→
165→    // Parse first line — session metadata
166→    const meta = parseSessionMeta(lines[0]);
167→    if (!meta) return null;
168→
169→    const sessionId = `codex:${meta.id}`;
170→
171→    // Parse remaining lines — events
172→    const messages: ParsedMessage[] = [];
173→    const usageEntries: CodexUsage[] = [];
174→    let model = meta.model || '';
175→    let lastTimestamp = new Date(meta.timestamp);
176→
177→    // Accumulator for current assistant turn
178→    let currentAssistantText = '';
179→    let currentToolCalls: ToolCall[] = [];
180→    let currentToolResults: ToolResult[] = [];
181→    let currentThinking: string | null = null;
182→    let turnUsage: CodexUsage | null = null;
183→    let toolCounter = 0;
184→
185→    function flushAssistantTurn(): void {
186→      const text = currentAssistantText.trim();
187→      if (!text && currentToolCalls.length === 0) return;
188→
189→      const msgUsage: MessageUsage | null = turnUsage ? {
190→        inputTokens: turnUsage.input_tokens || 0,
191→        outputTokens: turnUsage.output_tokens || 0,
192→        cacheCreationTokens: 0,
193→        cacheReadTokens: turnUsage.cached_input_tokens || 0,
194→        model: model || 'unknown',
195→        estimatedCostUsd: 0,
196→      } : null;
197→
198→      messages.push({
199→        id: `codex-assistant-${messages.length}`,
200→        sessionId: sessionId,
201→        type: 'assistant',
202→        content: text.slice(0, 10000),
203→        thinking: currentThinking,
204→        toolCalls: [...currentToolCalls],
205→        toolResults: [...currentToolResults],
206→        usage: msgUsage,
207→        timestamp: lastTimestamp,
208→        parentId: null,
209→      });
210→
211→      // Reset accumulators
212→      currentAssistantText = '';
213→      currentToolCalls = [];
214→      currentToolResults = [];
215→      currentThinking = null;
216→      turnUsage = null;
217→    }
218→
219→    for (let i = 1; i < lines.length; i++) {
220→      const line = lines[i];
221→      let event: CodexRolloutLine;
222→      try {
223→        event = JSON.parse(line) as CodexRolloutLine;
224→      } catch {
225→        continue;
226→      }
227→
228→      // Unwrap RolloutLine envelope if present
229→      const eventType = event.type;
230→      const payload = (event.payload || event) as Record<string, unknown>;
231→
232→      // Handle different event types
233→      const innerType = (payload.type as string) || eventType;
234→
235→      switch (innerType) {
236→        case 'message': {
237→          // response_item events: payload.type = "message", payload.role = "user"|"assistant"|"developer"
238→          const role = payload.role as string;
239→          if (role === 'user') {
240→            flushAssistantTurn();
241→            const userContent = extractUserContent(payload);
242→            if (userContent) {
243→              messages.push({
244→                id: (payload.id as string) || `codex-user-${messages.length}`,
245→                sessionId: sessionId,
246→                type: 'user',
247→                content: userContent.slice(0, 10000),
248→                thinking: null,
249→                toolCalls: [],
250→                toolResults: [],
251→                usage: null,
252→                timestamp: parseTimestamp(payload) || lastTimestamp,
253→                parentId: null,
254→              });
255→              lastTimestamp = messages[messages.length - 1].timestamp;
256→            }
257→          } else if (role === 'assistant') {
258→            const assistantContent = extractUserContent(payload);
259→            if (assistantContent) {
260→              currentAssistantText += assistantContent + '\n';
261→            }
262→          }
263→          // role === 'developer' = system/context messages — skip
264→          break;
265→        }
266→
267→        case 'user_message':
268→        case 'userMessage': {
269→          // Flush any pending assistant turn
270→          flushAssistantTurn();
271→
272→          const userContent = extractUserContent(payload);
273→          if (userContent) {
274→            messages.push({
275→              id: (payload.id as string) || `codex-user-${messages.length}`,
276→              sessionId: sessionId,
277→              type: 'user',
278→              content: userContent.slice(0, 10000),
279→              thinking: null,
280→              toolCalls: [],
281→              toolResults: [],
282→              usage: null,
283→              timestamp: parseTimestamp(payload) || lastTimestamp,
284→              parentId: null,
285→            });
286→            lastTimestamp = messages[messages.length - 1].timestamp;
287→          }
288→          break;
289→        }
290→
291→        case 'agent_message':
292→        case 'agentMessage':
293→        case 'item.completed': {
294→          const item = (payload.item || payload) as CodexItem;
295→          const itemType = item.type || innerType;
296→
297→          if (itemType === 'agent_message' || itemType === 'agentMessage') {
298→            currentAssistantText += (item.text || (payload.text as string) || '') + '\n';
299→          } else if (itemType === 'command_execution' || itemType === 'commandExecution') {
300→            toolCounter++;
301→            currentToolCalls.push({
302→              id: item.id || `codex-tool-${toolCounter}`,
303→              name: 'shell',
304→              input: { command: item.command || '', cwd: item.cwd || '' },
305→            });
306→            if (item.aggregatedOutput) {
307→              currentToolResults.push({
308→                toolUseId: item.id || `codex-tool-${toolCounter}`,
309→                output: (item.aggregatedOutput || '').slice(0, 1000),
310→              });
311→            }
312→          } else if (itemType === 'file_change' || itemType === 'fileChange') {
313→            if (item.changes) {
314→              for (const change of item.changes) {
315→                toolCounter++;
316→                currentToolCalls.push({
317→                  id: `codex-file-${toolCounter}`,
318→                  name: 'apply_patch',
319→                  input: { path: change.path, kind: change.kind },
320→                });
321→                if (change.diff) {
322→                  currentToolResults.push({
323→                    toolUseId: `codex-file-${toolCounter}`,
324→                    output: change.diff.slice(0, 1000),
325→                  });
326→                }
327→              }
328→            }
329→          } else if (itemType === 'mcp_tool_call' || itemType === 'mcpToolCall') {
330→            toolCounter++;
331→            currentToolCalls.push({
332→              id: item.id || `codex-mcp-${toolCounter}`,
333→              name: item.tool || 'mcp_tool',
334→              input: item.arguments || {},
335→            });
336→            if (item.result) {
337→              currentToolResults.push({
338→                toolUseId: item.id || `codex-mcp-${toolCounter}`,
339→                output: (item.result || '').slice(0, 1000),
340→              });
341→            }
342→          } else if (itemType === 'reasoning') {
343→            currentThinking = item.summary || (item.text as unknown as string) || null;
344→          }
345→          break;
346→        }
347→
348→        case 'turn.completed': {
349→          const usage = (payload.usage || payload) as CodexUsage;
350→          if (usage.input_tokens) {
351→            turnUsage = usage;
352→            usageEntries.push(usage);
353→          }
354→          if ((payload as Record<string, unknown>).model) {
355→            model = (payload as Record<string, unknown>).model as string;
356→          }
357→
358→          // Flush assistant turn at turn boundary
359→          flushAssistantTurn();
360→          break;
361→        }
362→
363→        case 'turn.started':
364→        case 'thread.started':
365→        case 'session_meta':
366→          // Lifecycle events — skip
367→          break;
368→      }
369→    }
370→
371→    // Flush any remaining assistant content
372→    flushAssistantTurn();
373→
374→    if (messages.length === 0) return null;
375→
376→    // Build session
377→    const userMessages = messages.filter(m => m.type === 'user');
378→    const assistantMessages = messages.filter(m => m.type === 'assistant');
379→    const toolCallCount = messages.reduce((sum, m) => sum + m.toolCalls.length, 0);
380→
381→    const timestamps = messages.map(m => m.timestamp.getTime()).filter(t => t > 0);
382→    const startedAt = timestamps.length > 0 ? new Date(Math.min(...timestamps)) : new Date(meta.timestamp);
383→    const endedAt = timestamps.length > 0 ? new Date(Math.max(...timestamps)) : lastTimestamp;
384→
385→    // Build session usage from accumulated turn usage
386→    const totalInput = usageEntries.reduce((s, u) => s + (u.input_tokens || 0), 0);
387→    const totalOutput = usageEntries.reduce((s, u) => s + (u.output_tokens || 0), 0);
388→    const totalCached = usageEntries.reduce((s, u) => s + (u.cached_input_tokens || 0), 0);
389→
390→    const usage: SessionUsage | undefined = totalInput > 0 ? {
391→      totalInputTokens: totalInput,
392→      totalOutputTokens: totalOutput,
393→      cacheCreationTokens: 0,
394→      cacheReadTokens: totalCached,
395→      estimatedCostUsd: 0, // TODO: Codex pricing not public
396→      modelsUsed: model ? [model] : [],
397→      primaryModel: model || 'unknown',
398→      usageSource: 'jsonl',
399→    } : undefined;
400→
401→    const projectPath = meta.cwd || 'codex://unknown';
402→    const projectName = path.basename(projectPath);
403→
404→    const session: ParsedSession = {
405→      id: sessionId,
406→      projectPath,
407→      projectName,
408→      summary: null,
409→      generatedTitle: null,
410→      titleSource: null,
411→      sessionCharacter: null,
412→      startedAt,
413→      endedAt,
414→      messageCount: messages.length,
415→      userMessageCount: userMessages.length,
416→      assistantMessageCount: assistantMessages.length,
417→      toolCallCount,
418→      gitBranch: null,
419→      claudeVersion: meta.cli_version || null,
420→      sourceTool: 'codex-cli',
421→      usage,
422→      messages,
423→    };
424→
425→    // Generate title and character
426→    const titleResult = generateTitle(session);
427→    session.generatedTitle = titleResult.title;
428→    session.titleSource = titleResult.source;
429→    session.sessionCharacter = titleResult.character || detectSessionCharacter(session);
430→
431→    return session;
432→  } catch {
433→    return null;
434→  }
435→}
