437→// ---------------------------------------------------------------------------
438→// Parsing helpers
439→// ---------------------------------------------------------------------------
440→
441→function parseSessionMeta(line: string): CodexSessionMeta | null {
442→  try {
443→    const parsed = JSON.parse(line);
444→    // Handle RolloutLine envelope
445→    if (parsed.payload && parsed.type === 'session_meta') {
446→      return parsed.payload as CodexSessionMeta;
447→    }
448→    // Handle bare session_meta (legacy or direct)
449→    if (parsed.type === 'session_meta' || parsed.id) {
450→      return parsed as CodexSessionMeta;
451→    }
452→    return null;
453→  } catch {
454→    return null;
455→  }
456→}
457→
458→function extractUserContent(payload: Record<string, unknown>): string | null {
459→  if (typeof payload.text === 'string') return payload.text;
460→  if (typeof payload.content === 'string') return payload.content;
461→  if (Array.isArray(payload.content)) {
462→    return (payload.content as Array<Record<string, string>>)
463→      .filter(c => c.type === 'text')
464→      .map(c => c.text)
465→      .join('\n');
466→  }
467→  // Nested in item
468→  const item = payload.item as Record<string, unknown> | undefined;
469→  if (item) return extractUserContent(item);
470→  return null;
471→}
472→
473→function parseTimestamp(payload: Record<string, unknown>): Date | null {
474→  const ts = payload.timestamp || payload.createdAt;
475→  if (!ts) return null;
476→  const d = new Date(ts as string | number);
477→  return isNaN(d.getTime()) ? null : d;
478→}
